module RefModule (
    input wire D,
    input wire EN,
    output reg Q,
    output reg Q_not
);
    reg master_Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge EN or posedge dbg_halt) begin
        master_Q <= D;
    end

    always @(negedge EN) begin
        Q <= master_Q;
        Q_not <= ~master_Q;
    end
endmodule
